INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (1, '1회섭취참고량', 'RAFOS', 'Reference Amount For One Serving', '一回攝取參考量. 만 3세 이상 소비계층이 통상적으로 소비하는 식품별 1회 섭취량과 시장조사 결과 등을 바탕으로 설정한 값을 말한다. ', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (2, 'GIS', 'GIS', 'Geographic Information System', 'GIS. 지리정보시스템(Geographic Information System) 지도에 관한 속성 정보를 컴퓨터를 이용해서 해석하는 지도 정보 시스템', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (3, 'HTML', 'HTML', 'Hypertext Markup Language', 'HTML. 하이퍼링크를 사용하는 컴퓨터 언어. 홈페이지 제작에 주로 사용하는 언어로 표시가 있는 글을 선택하면 그것과 연결되어 있는 내용을 보여 주거나 연결되어 있는 프로그램을 실행', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (4, 'IP', 'IP', 'Internet Protocol', 'IP. OSI 모델의 제3계층(네트워크층)에 해당되는 프로토콜로 IP계층에 따라 다른 네트워크 간 패킷의 전송, 즉 경로 제어를 위한 규약', 'N', '-', '아이피', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (5, 'MAC', 'MAC', 'Medium Access Control', 'MAC. OSI 기본 참조 모델의 데이터 링크 계층의 일부로서, 동일한 매체를 여러 노드가 공유하는 특성상에 존재하는 구내 정보 통신망(LAN) 고유의 계층', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
