INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (13, '가상', 'VR', 'Virtual', '假象. 주관적으로는 실제 있는 것처럼 보이나 객관적으로는 존재하지 않는 거짓 현상. 假想. 사실이 아니거나 사실 여부가 분명하지 않은 것을 사실이라고 가정하여 생각함', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
