INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (755, '일곱번째', 'SVNTH', 'seventh', '일곱번째', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (756, 'ＰＯＲＴ', 'ＰＯＲＴ', 'ＰＯＲＴ', '포트는 운영 체제 통신의 종단점이다. 이 용어는 하드웨어 장치에도 사용되지만,소프트웨어에서는 네트워크 서비스나 특정 프로세스를 식별하는 논리 단위이다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (757, '디렉토리', 'ＤＩＲ', 'directory', '디렉토리(영어: directory, 문화어: 등록부)는 컴퓨팅에서 파일을 분류하기 위해 사용하는 이름공간이다. 파일 시스템안에서 파일과 다른 하부 디렉토리들로 구성된다. 수많은 컴퓨터에서 디렉토리는 폴더(folder) 또는 카탈로그(catalog)라고도 한다. 표준국어대사전에서는 디렉터리로 등재하고 있으며[1], 마이크로소프트 윈도우에서는 폴더와 디렉터리[2]라는 용어가 번갈아가며 쓰인다.', 'N', '-', '폴더、카탈로그', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (758, '재활용', 'RCYCL', 'reCycle', '"Recycling"은 재활용을 뜻하는 단어입니다. 재활용은 기존에 사용하던 제품이나 물건을 다시 수집하여 재사용하거나 새로운 제품으로 만드는 것을 말합니다. 예를 들어, 쓰레기통에 버린 플라스틱 병이나 종이컵을 수거하여 새로운 플라스틱 제품이나 종이 제품으로 만들거나, 전자 제품을 분해하여 유용한 부품을 다시 활용하는 것도 재활용의 일종입니다. 재활용은 자원을 보존하고 쓰레기 처리 비용을 절감하는 등 환경 보호와 경제성을 동시에 실현할 수 있는 방법입니다.', 'N', '-', '재사용', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (759, '비활성', 'NACTVTN', 'Non-Activation', '活性. 어떤 시스템이 동작할 수 있는 수준에 있는 것의 반댓말', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (760, '도구', 'TL', 'tool', '도구(道具)는 어떤 일을 할 때 이용하는 소규모 장치를 말한다. 도구를 활용함으로써 사람이 일을 할 때 노력을 덜 들이고 편하게 할 수 있다. 예를 들면 음식을 만들 때 사용하는 칼이나 식사를 할 때 사용하는 수저가 그 예가 되겠다.', 'N', '-', '툴', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (761, '테넌트', 'TNNT', 'tenant ', '임차인, 세입자, 입주자', 'N', '-', '임차인,세입자,입주자', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (762, '신호', 'SGNL', 'signal', '신호(信號)는 일정한 부호, 표지, 소리, 몸짓 따위로 특정한 내용 또는 정보를 전달하거나 지시를 함. 또는 그렇게 하는 데 쓰는 부호.', 'N', '-', '기호, 부호, 신호, 표지, 간판, 표징', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (763, '저장소', 'REPO', 'Repository', '파일이나 데이터 버전 관리하고 저장하는 공간으로 소스 코드, 문서, 이미지 등 다양한 종류의 파일을 저장하고 버전관리를 위해 사용될 수 있다. 버전관리와 같은, 파일/데이터의 관리를 위한 목적으로 사용된다.', 'N', '-', '레파지토리,리파지토리,리포', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (764, '시도', 'TRY', 'try', '어떤 것을 행하기 위해 실제로 하는 것.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (765, '정책', 'PLCY', 'Policy', '정부 또는 각종 공/사부문 단체가 그들의 당면한 문제를 해결하기 위한 행동 방침을 뜻한다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (766, '파이프라인', 'PPLN', 'PIPELINE', '컴퓨터 과학에서 파이프라인(영어: pipeline) 또는 데이터 파이프라인(data pipeline)[1]은 한 데이터 처리 단계의 출력이 다음 단계의 입력으로 이어지는 형태로 연결된 구조를 가리킨다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (767, '스크립트', 'SCRPT', 'SCRIPT', '영화나 방송의 대본(臺本)·각본(脚本).', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (768, '티켓', 'TCKT', 'TICKET', ' (차, 비행기, 극장, 전시회 따위의) 승차권, 입장권, 표.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (769, '워크플로', 'WRKFLW', 'workflow', '워크플로(영어: workflow)는 작업 절차를 통한 정보 또는 업무의 이동을 의미하며, 작업 흐름이라고도 부른다. 더 자세히 말해, 워크플로는 작업 절차의 운영적 측면이다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (770, '다음', 'NXT', 'next', '시간적·공간적 차례에서, 기준의 바로 뒤.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (771, '버전', 'VSRN', 'version', '어떤 프로그램을 수정, 개선하여 완성한 것. 새로워질 때마다 번호를 늘려 나감. 판(版).', 'N', '-', '판', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (772, '모듈', 'MODULE', 'module', '인지과학에서 정신의 모듈성은 정신이 서로 독립적이고, 닫혀있고, 영역에 따라 다른 역할을 한다는 의미이다. 전산학에서는 모듈성 은 컴퓨터 프로그램의 한 속성으로, 모듈이라고 불리는 것으로 서로 분리되어 작성되는 성질이다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (773, '필요', 'NCSSRY', 'necessary', '꼭 있어야 하거나 갖추어져야 하는 상태에 있는 것. 수요(須要).', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (774, '호스트', 'HOST', 'host', '호스트는 인터넷 (또는 로컬 네트워크)에 연결된 장치입니다. 서버라는 일부 호스트는 웹페이지 제공, 파일 및 이메일 저장과 같은 추가 서비스를 제공합니다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (775, '포트', 'PORT', 'port', '포트는 “논리적인 접속장소”를 뜻하며, 인터넷 프로토콜인 TCP/IP를 사용할 때 클라이언트 프로그램이 네트워크 상의 특정 서버 프로그램을 지정하는 방법으로 사용한다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (776, '허용', 'ENBLE', 'ENABLE', '무엇이 그러하다고 받아들임 또는 무엇을 그렇게 하도록 함.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (777, '신뢰', 'TRST', 'trust', ' 信賴 : 상대방을 굳게 믿고 의지하는 마음.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (778, '안전한', 'SECURE', 'SECURE', '안전하게 하다 (매듭,토대가) 안정된 튼튼한 얻다 확보하다 획득하다', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (779, '대기', 'WAIT', 'wait', '待機 / 待期 : 때나 기회를 기다림. 또는 명령이나 신호를 기다림.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (780, '레벨', 'LV', 'LEVEL', ' 수준, 단계, 수평기 등을 의미하는 영어 단어이다', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (781, '깊이', 'DPTH', 'depth', '주어진 위나 혹은 겉의 한 곳에서 바닥 또는 속까지 이르는 거리', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
INSERT INTO DICT (NO, CMN_STD_WORD_NM, CMN_STD_WORD_AKTAA, CMN_STD_WORD_ENG, CMN_STD_WORD_EXPLN, FRM_WORD_YN, CMN_STD_DMN_CLSF, TRM_ALP_EQVL_LIST, FBDWD_LIST, REG_DT, RGTR_ID) VALUES (782, '가상머신', 'VM', 'VIRTUAL MACHINE', '물리적으로 존재하는 컴퓨터가 아닌, 다른 컴퓨터가 만들어내는 가상의 컴퓨터를 말한다. 즉 컴퓨터 안에 있는 컴퓨터인 셈이다. 그래서 가상 머신으로 돌린 컴퓨터에서 가상 머신을 돌리는 것도 가능하다. 또는 자바 가상 머신처럼 특정 언어로 쓰여진 프로그램을 돌리기 위한 인터프리터를 가리키기도 한다.', 'N', '-', '-', '-', '2026-04-15 08:29:54', 'SYSTEM');
